module RefModule(
    input wire ctrl,
    input wire data_in,
    output reg data_out
);
  wire _tap_ctrl = ctrl & {1{1'b1}};


always @(*) begin
    if (ctrl) begin
        data_out = data_in; // Store input when control is high
    end
    // No else needed as data_out will hold its previous value when ctrl is low
end

endmodule
